INSERT INTO "Incident" ("id", "incidentNumber", "title", "description", "type", "severity", "status", "location", "occurredAt", "reportedAt", "resolvedAt", "isAutoEscalated", "aiAnalysis", "siteId", "reporterId", "assigneeId", "createdAt", "updatedAt", "idempotencyKey") VALUES ('cmpfqx08c003fhpgjth75nnto', 'INC-2026-0011', 'Pipeline Leak — PL-001 at km 142.5', 'AI-detected pipeline leak with 95% confidence.

Critical leak detected at PP-03 (142.5 km) with catastrophic pressure drop of 21.92 bar over 83 minutes, falling from 72.53 to 50.61 bar and breaching minimum safe pressure of 60 bar.

Root Cause: Major pipeline rupture or catastrophic valve failure at PP-03 location - the isolated nature of the pressure drop (upstream and downstream points remain normal) indicates localized structural failure rather than operational issue. Given 8-year pipeline age and desert conditions, possible causes include: external corrosion, third-party damage, or weld failure.', 'PIPELINE_LEAK', 'CRITICAL', 'REPORTED', 'PL-001 — km 142.5', 1779383371115, 1779383371116, NULL, 1, '{"leakAlertId":"cmpfqx087003dhpgjboa0k63m","pipelineId":"pl-001","confidence":0.95,"predictions":["Gas release rate estimated at 15,000-25,000 m³/hour based on pressure drop velocity - immediate environmental and safety hazard within 500m radius","Downstream pressure at PP-04 and PP-05 will begin dropping within 30-45 minutes as the leak propagates if not isolated immediately","Complete pipeline depressurization at PP-03 segment expected within 2-3 hours if emergency shutdown not executed"],"immediateActions":["EMERGENCY SHUTDOWN: Immediately close isolation valves upstream (between PP-02 and PP-03) and downstream (between PP-03 and PP-04) to isolate the 71.25 km segment","Evacuate all personnel within 1 km radius of PP-03 location (22.89585°N, 56.579°E) and establish exclusion zone - notify Oman Civil Defence and Royal Oman Police","Deploy emergency response team with gas detection equipment to PP-03 location - assess for fire/explosion risk and environmental impact to surrounding desert area"]}', 'site-khazzan', 'user-admin-001', NULL, 1779383371116, 1779383371116, NULL);
INSERT INTO "Incident" ("id", "incidentNumber", "title", "description", "type", "severity", "status", "location", "occurredAt", "reportedAt", "resolvedAt", "isAutoEscalated", "aiAnalysis", "siteId", "reporterId", "assigneeId", "createdAt", "updatedAt", "idempotencyKey") VALUES ('cmpgyek56001jhp0cr1s85ifd', 'INC-2026-0012', '[AUTO] Pipeline Leak — PL-001 at km 35.6', 'AEGIS autonomously detected a pipeline leak (confidence 95%).

Critical leak detected between PP-01 and PP-02. Catastrophic pressure drop of 22 bar across 4 downstream sensors while PP-01 remains stable, indicating major rupture approximately 35.6 km from pipeline origin.

Root cause: Major pipeline rupture or catastrophic valve failure between PP-01 (km 0) and PP-02 (km 71.25). The uniform 22-bar pressure drop across all downstream points while upstream remains normal indicates complete loss of pressure integrity in the segment, likely full-bore rupture or complete valve seat failure.', 'PIPELINE_LEAK', 'CRITICAL', 'REPORTED', 'PL-001 — km 35.6', 1779456413562, 1779456413563, NULL, 1, '{"leakAlertId":"cmpgyek53001hhp0crgddr4lu","leakDetected":true,"confidence":0.95,"severity":"CRITICAL","estimatedKmFromStart":35.6,"estimatedLat":21.811463,"estimatedLng":56.48225,"affectedPoints":["PL-001-PP-02","PL-001-PP-03","PL-001-PP-04","PL-001-PP-05"],"pressureDrop":22,"summary":"Critical leak detected between PP-01 and PP-02. Catastrophic pressure drop of 22 bar across 4 downstream sensors while PP-01 remains stable, indicating major rupture approximately 35.6 km from pipeline origin.","summaryAr":"تم اكتشاف تسرب حرج بين PP-01 و PP-02. انخفاض كارثي في الضغط بمقدار 22 بار عبر 4 مستشعرات لاحقة بينما يظل PP-01 مستقرًا، مما يشير إلى تразрыв كبير على بعد حوالي 35.6 كم من بداية خط الأنابيب.","rootCause":"Major pipeline rupture or catastrophic valve failure between PP-01 (km 0) and PP-02 (km 71.25). The uniform 22-bar pressure drop across all downstream points while upstream remains normal indicates complete loss of pressure integrity in the segment, likely full-bore rupture or complete valve seat failure.","immediateActions":["EMERGENCY SHUTDOWN: Immediately isolate PL-001 at source and close all block valves upstream of PP-01","EVACUATE: Establish 500m exclusion zone around estimated leak location (21.811°N, 56.482°E) and evacuate all personnel","DISPATCH: Send emergency response team with gas detection equipment to km 35.6 sector for visual confirmation and containment","NOTIFY: Alert OQ Emergency Operations Center, Civil Defense, and Ministry of Energy - declare Level 1 emergency","MONITOR: Continuous surveillance of PP-01 pressure decay rate to confirm isolation effectiveness"]}', 'site-khazzan', 'cmpgyek4x001fhp0c6awn2xhs', NULL, 1779456413563, 1779456413563, 'inc-7b59cc9b95bf60a413170311a2907aed');
