INSERT INTO "AIDecision" ("id", "type", "provider", "modelUsed", "inputData", "outputData", "reasoning", "confidence", "tokensInput", "tokensOutput", "durationMs", "autonomous", "requiresHuman", "visionDetectionId", "telemetryId", "alertId", "incidentId", "createdAt") VALUES ('cmpfgltbd003ahpp6km8ozx17', 'PIPELINE_LEAK_ANALYSIS', 'CLAUDE', 'claude-sonnet-4-5-20250929', '"{\"pipelineId\":\"pl-001\",\"dataSummary\":[{\"code\":\"PL-001-PP-01\",\"positionKm\":0,\"latitude\":21.45,\"longitude\":56.45,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"73.03\",\"time\":\"2026-05-21T10:43:45.360Z\"},\"lastReading\":{\"pressure\":\"73.03\",\"time\":\"2026-05-21T10:43:45.360Z\"},\"averagePressure\":\"73.03\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-02\",\"positionKm\":71.25,\"latitude\":22.172925,\"longitude\":56.5145,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"72.26\",\"time\":\"2026-05-21T10:43:45.368Z\"},\"lastReading\":{\"pressure\":\"72.26\",\"time\":\"2026-05-21T10:43:45.368Z\"},\"averagePressure\":\"72.26\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-03\",\"positionKm\":142.5,\"latitude\":22.89585,\"longitude\":56.579,\"readingsCount\":12,\"firstReading\":{\"pressure\":\"72.24\",\"time\":\"2026-05-21T10:55:20.699Z\"},\"lastReading\":{\"pressure\":\"64.66\",\"time\":\"2026-05-21T12:17:50.699Z\"},\"averagePressure\":\"69.68\",\"pressureDropBar\":\"7.59\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-04\",\"positionKm\":213.75,\"latitude\":23.618775,\"longitude\":56.6435,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"70.82\",\"time\":\"2026-05-21T10:43:45.379Z\"},\"lastReading\":{\"pressure\":\"70.82\",\"time\":\"2026-05-21T10:43:45.379Z\"},\"averagePressure\":\"70.82\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-05\",\"positionKm\":285,\"latitude\":24.3417,\"longitude\":56.708,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"73.42\",\"time\":\"2026-05-21T10:43:45.385Z\"},\"lastReading\":{\"pressure\":\"73.42\",\"time\":\"2026-05-21T10:43:45.385Z\"},\"averagePressure\":\"73.42\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false}]}"', '"{\"leakDetected\":true,\"confidence\":0.75,\"severity\":\"MEDIUM\",\"estimatedKmFromStart\":142.5,\"estimatedLat\":22.89585,\"estimatedLng\":56.579,\"affectedPoints\":[\"PL-001-PP-03\"],\"pressureDrop\":7.59,\"summary\":\"Potential leak detected at PP-03 (142.5 km) with 7.59 bar pressure drop over 82 minutes. Downstream points show stable pressures, suggesting localized anomaly requiring immediate investigation.\",\"summaryAr\":\"تم اكتشاف تسرب محتمل عند نقطة PP-03 (142.5 كم) مع انخفاض ضغط 7.59 بار خلال 82 دقيقة. نقاط المصب تظهر ضغوطاً مستقرة، مما يشير إلى حالة شاذة موضعية تتطلب تحقيقاً فورياً.\",\"rootCause\":\"Localized pressure anomaly at PP-03 sensor - possible leak, sensor malfunction, or valve operation. The isolated nature (no downstream propagation) suggests either a small leak with flow compensation or sensor calibration drift in desert conditions.\",\"predictions\":[\"If leak is real: pressure at PP-03 will continue declining below 60 bar within 4-6 hours\",\"If sensor malfunction: pressure reading will remain erratic while adjacent points stay stable\",\"Downstream points PP-04 and PP-05 may show delayed pressure drops within 2-3 hours if leak expands\"],\"immediateActions\":[\"Deploy field inspection team to PP-03 location (22.89585°N, 56.579°E) within 2 hours for visual inspection and leak detection survey\",\"Verify PP-03 sensor calibration and compare with portable pressure gauge readings\",\"Increase monitoring frequency at PP-03, PP-04 to 5-minute intervals for next 6 hours\",\"Notify MoEM Emergency Response Center and OQ Operations Control Room per Oman pipeline safety protocols\",\"Prepare isolation procedures for section PP-02 to PP-04 (71.25-213.75 km) if pressure continues declining\"],\"preventiveActions\":[\"Implement automated sensor validation algorithms to cross-check readings against adjacent points and detect anomalies earlier\",\"Schedule accelerated integrity assessment (ILI smart pig run) for this 2018-installed pipeline section given 8-year service in harsh desert conditions\",\"Enhance cathodic protection monitoring at PP-03 area to prevent external corrosion in high-temperature desert environment\"]}"', 'Potential leak detected at PP-03 (142.5 km) with 7.59 bar pressure drop over 82 minutes. Downstream points show stable pressures, suggesting localized anomaly requiring immediate investigation.', 0.75, NULL, NULL, NULL, 1, 0, NULL, NULL, NULL, NULL, 1779366052777);
INSERT INTO "AIDecision" ("id", "type", "provider", "modelUsed", "inputData", "outputData", "reasoning", "confidence", "tokensInput", "tokensOutput", "durationMs", "autonomous", "requiresHuman", "visionDetectionId", "telemetryId", "alertId", "incidentId", "createdAt") VALUES ('cmpfkcum2000ghpc0bauk5bw9', 'PIPELINE_LEAK_ANALYSIS', 'CLAUDE', 'claude-sonnet-4-5-20250929', '"{\"pipelineId\":\"pl-001\",\"dataSummary\":[{\"code\":\"PL-001-PP-01\",\"positionKm\":0,\"latitude\":21.45,\"longitude\":56.45,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"73.85\",\"time\":\"2026-05-21T12:46:09.932Z\"},\"lastReading\":{\"pressure\":\"73.85\",\"time\":\"2026-05-21T12:46:09.932Z\"},\"averagePressure\":\"73.85\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-02\",\"positionKm\":71.25,\"latitude\":22.172925,\"longitude\":56.5145,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"70.94\",\"time\":\"2026-05-21T12:46:09.938Z\"},\"lastReading\":{\"pressure\":\"70.94\",\"time\":\"2026-05-21T12:46:09.938Z\"},\"averagePressure\":\"70.94\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-03\",\"positionKm\":142.5,\"latitude\":22.89585,\"longitude\":56.579,\"readingsCount\":12,\"firstReading\":{\"pressure\":\"73.29\",\"time\":\"2026-05-21T12:42:59.699Z\"},\"lastReading\":{\"pressure\":\"58.78\",\"time\":\"2026-05-21T14:05:29.699Z\"},\"averagePressure\":\"67.40\",\"pressureDropBar\":\"14.50\",\"currentStatus\":\"CRITICAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":true},{\"code\":\"PL-001-PP-04\",\"positionKm\":213.75,\"latitude\":23.618775,\"longitude\":56.6435,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"73.18\",\"time\":\"2026-05-21T12:46:09.950Z\"},\"lastReading\":{\"pressure\":\"73.18\",\"time\":\"2026-05-21T12:46:09.950Z\"},\"averagePressure\":\"73.18\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-05\",\"positionKm\":285,\"latitude\":24.3417,\"longitude\":56.708,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"73.89\",\"time\":\"2026-05-21T12:46:09.956Z\"},\"lastReading\":{\"pressure\":\"73.89\",\"time\":\"2026-05-21T12:46:09.956Z\"},\"averagePressure\":\"73.89\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false}]}"', '"{\"leakDetected\":true,\"confidence\":0.92,\"severity\":\"CRITICAL\",\"estimatedKmFromStart\":142.5,\"estimatedLat\":22.89585,\"estimatedLng\":56.579,\"affectedPoints\":[\"PL-001-PP-03\"],\"pressureDrop\":14.5,\"summary\":\"CRITICAL leak detected at PP-03 (km 142.5) with 14.5 bar pressure drop over 82 minutes, falling below safe minimum of 60 bar to 58.78 bar. Immediate shutdown required.\",\"summaryAr\":\"تم اكتشاف تسرب حرج عند نقطة PP-03 (كم 142.5) مع انخفاض ضغط 14.5 بار خلال 82 دقيقة، وانخفض إلى 58.78 بار تحت الحد الآمن. يتطلب إيقاف فوري.\",\"rootCause\":\"Major pipeline rupture or catastrophic valve failure at PP-03. The 14.5 bar drop in 82 minutes with pressure falling below safe minimum (58.78 bar) indicates significant gas escape. Upstream (PP-01, PP-02) and downstream (PP-04, PP-05) points remain stable, isolating the anomaly to PP-03 location.\",\"predictions\":[\"Continued pressure decline at PP-03 will reach critical system failure (<50 bar) within 2-3 hours if not isolated\",\"Gas release rate estimated at 180-250 kg/s based on pressure drop velocity, creating significant safety hazard zone (500m+ radius)\",\"Downstream supply disruption to Sohar industrial facilities imminent; upstream Khazzan production may require emergency shutdown\"],\"immediateActions\":[\"EMERGENCY: Activate ESD (Emergency Shutdown) valves to isolate segment between PP-02 (km 71.25) and PP-04 (km 213.75) immediately\",\"Evacuate all personnel within 1 km radius of PP-03 location (22.89585°N, 56.579°E) and establish exclusion zone per MoEM emergency protocols\",\"Deploy emergency response team with gas detection equipment to PP-03 site; notify Oman Civil Defence and MoEM Emergency Operations Center\",\"Initiate controlled depressurization of isolated segment and monitor for ignition sources; prepare firefighting resources\",\"Contact Sohar Port and Freezone industrial customers to implement gas supply contingency plans\"],\"preventiveActions\":[\"Conduct immediate ultrasonic inspection of all pipeline segments installed in 2018 (same vintage as failed section) focusing on weld integrity and corrosion under insulation\",\"Implement real-time pressure monitoring with 5-minute interval alerts (current system appears to have delayed detection - 82 minutes elapsed)\",\"Review and upgrade cathodic protection system effectiveness in desert soil conditions between km 100-180 where soil resistivity may compromise corrosion protection\",\"Schedule emergency pipeline integrity assessment using inline inspection (ILI) smart pig for entire PL-001 route within 30 days post-repair\"]}"', 'CRITICAL leak detected at PP-03 (km 142.5) with 14.5 bar pressure drop over 82 minutes, falling below safe minimum of 60 bar to 58.78 bar. Immediate shutdown required.', 0.92, NULL, NULL, NULL, 1, 1, NULL, NULL, NULL, NULL, 1779372353019);
INSERT INTO "AIDecision" ("id", "type", "provider", "modelUsed", "inputData", "outputData", "reasoning", "confidence", "tokensInput", "tokensOutput", "durationMs", "autonomous", "requiresHuman", "visionDetectionId", "telemetryId", "alertId", "incidentId", "createdAt") VALUES ('cmpfke6au001dhpc0clh884s0', 'PIPELINE_LEAK_ANALYSIS', 'CLAUDE', 'claude-sonnet-4-5-20250929', '"{\"pipelineId\":\"pl-001\",\"dataSummary\":[{\"code\":\"PL-001-PP-01\",\"positionKm\":0,\"latitude\":21.45,\"longitude\":56.45,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"73.85\",\"time\":\"2026-05-21T12:46:09.932Z\"},\"lastReading\":{\"pressure\":\"73.85\",\"time\":\"2026-05-21T12:46:09.932Z\"},\"averagePressure\":\"73.85\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-02\",\"positionKm\":71.25,\"latitude\":22.172925,\"longitude\":56.5145,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"70.94\",\"time\":\"2026-05-21T12:46:09.938Z\"},\"lastReading\":{\"pressure\":\"70.94\",\"time\":\"2026-05-21T12:46:09.938Z\"},\"averagePressure\":\"70.94\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-03\",\"positionKm\":142.5,\"latitude\":22.89585,\"longitude\":56.579,\"readingsCount\":12,\"firstReading\":{\"pressure\":\"73.24\",\"time\":\"2026-05-21T12:44:06.334Z\"},\"lastReading\":{\"pressure\":\"59.57\",\"time\":\"2026-05-21T14:06:36.334Z\"},\"averagePressure\":\"67.69\",\"pressureDropBar\":\"13.68\",\"currentStatus\":\"CRITICAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":true},{\"code\":\"PL-001-PP-04\",\"positionKm\":213.75,\"latitude\":23.618775,\"longitude\":56.6435,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"73.18\",\"time\":\"2026-05-21T12:46:09.950Z\"},\"lastReading\":{\"pressure\":\"73.18\",\"time\":\"2026-05-21T12:46:09.950Z\"},\"averagePressure\":\"73.18\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-05\",\"positionKm\":285,\"latitude\":24.3417,\"longitude\":56.708,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"73.89\",\"time\":\"2026-05-21T12:46:09.956Z\"},\"lastReading\":{\"pressure\":\"73.89\",\"time\":\"2026-05-21T12:46:09.956Z\"},\"averagePressure\":\"73.89\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false}]}"', '"{\"leakDetected\":true,\"confidence\":0.92,\"severity\":\"CRITICAL\",\"estimatedKmFromStart\":142.5,\"estimatedLat\":22.89585,\"estimatedLng\":56.579,\"affectedPoints\":[\"PL-001-PP-03\"],\"pressureDrop\":13.68,\"summary\":\"Critical leak detected at PP-03 (142.5 km) with 13.68 bar pressure drop over 82 minutes, falling below safe minimum of 60 bar to 59.57 bar. Immediate isolation required.\",\"summaryAr\":\"تم اكتشاف تسرب حرج عند نقطة PP-03 (142.5 كم) مع انخفاض ضغط 13.68 بار خلال 82 دقيقة، وانخفض إلى 59.57 بار تحت الحد الأدنى الآمن. يتطلب عزل فوري.\",\"rootCause\":\"Significant pipeline breach at PP-03 location - likely caused by external interference, corrosion failure, or mechanical damage given the rapid 13.68 bar pressure loss and breach of minimum safe operating pressure\",\"predictions\":[\"Continued pressure decline at PP-03 will reach critical levels below 55 bar within next 2-4 hours if not isolated\",\"Gas loss rate estimated at 6-8 bar/hour suggests medium to large diameter breach requiring immediate shutdown\",\"Downstream points PP-04 and PP-05 will experience pressure fluctuations within 30-60 minutes as system attempts to compensate\"],\"immediateActions\":[\"EMERGENCY: Isolate pipeline segment between PP-02 (71.25 km) and PP-04 (213.75 km) immediately via block valves\",\"Dispatch emergency response team to PP-03 coordinates (22.89585°N, 56.579°E) for visual inspection and leak confirmation\",\"Notify MoEM Emergency Operations Center and activate OQ Emergency Response Plan per Oman PDO-HSE-2024 protocols\",\"Establish 500-meter safety exclusion zone around PP-03 location and coordinate with Royal Oman Police for area evacuation\",\"Activate gas detection monitoring and deploy mobile units to assess environmental impact in surrounding area\"],\"preventiveActions\":[\"Conduct comprehensive integrity assessment of entire PL-001 pipeline using inline inspection tools (ILI) within next 30 days, focusing on corrosion and third-party damage indicators\",\"Implement enhanced cathodic protection monitoring at 50 km intervals and upgrade CP stations near PP-03 segment to prevent future corrosion-related failures\"]}"', 'Critical leak detected at PP-03 (142.5 km) with 13.68 bar pressure drop over 82 minutes, falling below safe minimum of 60 bar to 59.57 bar. Immediate isolation required.', 0.92, NULL, NULL, NULL, 1, 1, NULL, NULL, NULL, NULL, 1779372414822);
INSERT INTO "AIDecision" ("id", "type", "provider", "modelUsed", "inputData", "outputData", "reasoning", "confidence", "tokensInput", "tokensOutput", "durationMs", "autonomous", "requiresHuman", "visionDetectionId", "telemetryId", "alertId", "incidentId", "createdAt") VALUES ('cmpfpbr6t000ehpgjgdj1dxq7', 'PIPELINE_LEAK_ANALYSIS', 'CLAUDE', 'claude-sonnet-4-5-20250929', '"{\"pipelineId\":\"pl-002\",\"dataSummary\":[{\"code\":\"PL-002-PP-01\",\"positionKm\":0,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-02\",\"positionKm\":11.375,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-03\",\"positionKm\":22.75,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-04\",\"positionKm\":34.125,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-05\",\"positionKm\":45.5,\"status\":\"NO_DATA\"}]}"', '"{\"leakDetected\":false,\"confidence\":0,\"severity\":\"CRITICAL\",\"estimatedKmFromStart\":null,\"estimatedLat\":null,\"estimatedLng\":null,\"affectedPoints\":[\"PL-002-PP-01\",\"PL-002-PP-02\",\"PL-002-PP-03\",\"PL-002-PP-04\",\"PL-002-PP-05\"],\"pressureDrop\":0,\"summary\":\"CRITICAL SYSTEM FAILURE: All 5 pressure monitoring points on PL-002 Khazzan-Block61 Gas Gathering pipeline show NO_DATA status for the past 2 hours. Complete loss of telemetry indicates potential SCADA failure, power outage, or catastrophic pipeline event requiring immediate emergency response.\",\"summaryAr\":\"فشل حرج في النظام: جميع نقاط مراقبة الضغط الخمسة في خط أنابيب PL-002 خزان-بلوك61 لا تُظهر بيانات منذ ساعتين. فقدان كامل للقياس عن بُعد يشير إلى فشل نظام سكادا أو انقطاع الكهرباء أو حدث كارثي يتطلب استجابة طارئة فورية.\",\"rootCause\":\"Complete telemetry system failure across all monitoring points - possible causes: SCADA communication network failure, central power supply disruption to all RTUs, fiber optic cable damage, cyber security incident, or catastrophic pipeline rupture affecting all sensors simultaneously\",\"predictions\":[\"If SCADA/communication failure: Pipeline may be operating blind with unknown pressure conditions, risking overpressure or undetected leaks\",\"If power outage: RTUs offline but pipeline may be intact; restoration of power will reveal actual operating conditions\",\"If catastrophic rupture: Complete depressurization may have damaged all sensor infrastructure; gas release poses immediate safety and environmental hazard in desert environment\"],\"immediateActions\":[\"EMERGENCY: Activate Block 61 Emergency Response Plan immediately - dispatch field teams to all 5 pressure point locations for visual inspection\",\"Contact Khazzan operations control room - verify SCADA system status and initiate manual shutdown procedures if pipeline integrity cannot be confirmed within 15 minutes\",\"Alert MoEM (Ministry of Energy and Minerals) Emergency Operations Center per Oman petroleum regulations - report complete monitoring system failure\",\"Deploy helicopter surveillance along entire 45.5 km route to check for visible gas plumes, ground disturbance, or equipment damage\",\"Establish 500m exclusion zones around all pressure point locations until sensor status confirmed - coordinate with ROP (Royal Oman Police) for area security\"],\"preventiveActions\":[\"Implement redundant communication pathways for SCADA (satellite backup to fiber optic) to prevent complete telemetry blackouts on critical gas gathering systems\",\"Install independent battery backup systems (minimum 8-hour capacity) at each RTU location with solar charging capability suitable for Oman desert conditions\",\"Establish automated SMS/satellite alert system that triggers when >2 consecutive pressure points report NO_DATA status for >10 minutes\",\"Conduct quarterly SCADA system resilience testing including simulated communication failures and cyber attack scenarios per OQ HSSE standards\"]}"', 'CRITICAL SYSTEM FAILURE: All 5 pressure monitoring points on PL-002 Khazzan-Block61 Gas Gathering pipeline show NO_DATA status for the past 2 hours. Complete loss of telemetry indicates potential SCADA failure, power outage, or catastrophic pipeline event requiring immediate emergency response.', 0, NULL, NULL, NULL, 1, 1, NULL, NULL, NULL, NULL, 1779380700006);
INSERT INTO "AIDecision" ("id", "type", "provider", "modelUsed", "inputData", "outputData", "reasoning", "confidence", "tokensInput", "tokensOutput", "durationMs", "autonomous", "requiresHuman", "visionDetectionId", "telemetryId", "alertId", "incidentId", "createdAt") VALUES ('cmpfpc0jv000hhpgjj9dm77fj', 'PIPELINE_LEAK_ANALYSIS', 'CLAUDE', 'claude-sonnet-4-5-20250929', '"{\"pipelineId\":\"pl-002\",\"dataSummary\":[{\"code\":\"PL-002-PP-01\",\"positionKm\":0,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-02\",\"positionKm\":11.375,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-03\",\"positionKm\":22.75,\"latitude\":21.48,\"longitude\":56.495,\"readingsCount\":12,\"firstReading\":{\"pressure\":\"64.17\",\"time\":\"2026-05-21T15:02:20.524Z\"},\"lastReading\":{\"pressure\":\"58.37\",\"time\":\"2026-05-21T16:24:50.524Z\"},\"averagePressure\":\"62.61\",\"pressureDropBar\":\"5.80\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"55-75 bar\",\"outOfRange\":false},{\"code\":\"PL-002-PP-04\",\"positionKm\":34.125,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-05\",\"positionKm\":45.5,\"status\":\"NO_DATA\"}]}"', '"{\"leakDetected\":false,\"confidence\":0.35,\"severity\":null,\"estimatedKmFromStart\":null,\"estimatedLat\":null,\"estimatedLng\":null,\"affectedPoints\":[],\"pressureDrop\":5.8,\"summary\":\"Insufficient data for leak confirmation. Only 1 of 5 pressure points operational (PL-002-PP-03) showing 5.8 bar drop over 82 minutes, which is borderline but within acceptable operational variation without corroborating data from adjacent points.\",\"summaryAr\":\"بيانات غير كافية لتأكيد التسرب. نقطة قياس واحدة فقط من أصل 5 تعمل (PL-002-PP-03) تظهر انخفاضاً 5.8 بار خلال 82 دقيقة، وهو ضمن التباين التشغيلي المقبول دون بيانات داعمة من النقاط المجاورة.\",\"rootCause\":\"Critical sensor/communication failure across 80% of monitoring infrastructure (4 of 5 pressure points offline). The 5.8 bar drop at PP-03 could indicate normal operational fluctuation, minor leak, or sensor drift - impossible to determine without adjacent point data.\",\"predictions\":[\"If leak exists at PP-03 vicinity (22.75 km), downstream points PP-04 and PP-05 would show progressive pressure drops when restored\",\"Sensor/SCADA communication failure likely due to power supply issues, network disruption, or equipment malfunction in harsh desert conditions\",\"Pipeline operating within safe range (58.37 bar current vs 55-75 bar safe range) suggests system integrity maintained despite monitoring gaps\"],\"immediateActions\":[\"URGENT: Dispatch field technicians to restore PP-01, PP-02, PP-04, and PP-05 sensors immediately - blind operation violates MoEM monitoring requirements\",\"Conduct physical inspection at PP-03 location (21.48°N, 56.495°E, km 22.75) to verify pressure readings and check for visible gas release indicators\",\"Activate backup monitoring protocols and increase manual inspection frequency until full sensor network restored\"],\"preventiveActions\":[\"Implement redundant power systems (solar + battery backup) for all pressure monitoring points to prevent simultaneous communication failures in remote desert locations\",\"Establish automated alarm system that triggers when >2 consecutive pressure points go offline, ensuring rapid response to monitoring infrastructure failures\"]}"', 'Insufficient data for leak confirmation. Only 1 of 5 pressure points operational (PL-002-PP-03) showing 5.8 bar drop over 82 minutes, which is borderline but within acceptable operational variation without corroborating data from adjacent points.', 0.35, NULL, NULL, NULL, 1, 0, NULL, NULL, NULL, NULL, 1779380712139);
INSERT INTO "AIDecision" ("id", "type", "provider", "modelUsed", "inputData", "outputData", "reasoning", "confidence", "tokensInput", "tokensOutput", "durationMs", "autonomous", "requiresHuman", "visionDetectionId", "telemetryId", "alertId", "incidentId", "createdAt") VALUES ('cmpfpckp3000yhpgj56jrao3n', 'PIPELINE_LEAK_ANALYSIS', 'CLAUDE', 'claude-sonnet-4-5-20250929', '"{\"pipelineId\":\"pl-002\",\"dataSummary\":[{\"code\":\"PL-002-PP-01\",\"positionKm\":0,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-02\",\"positionKm\":11.375,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-03\",\"positionKm\":22.75,\"latitude\":21.48,\"longitude\":56.495,\"readingsCount\":12,\"firstReading\":{\"pressure\":\"65.81\",\"time\":\"2026-05-21T15:02:46.670Z\"},\"lastReading\":{\"pressure\":\"51.84\",\"time\":\"2026-05-21T16:25:16.670Z\"},\"averagePressure\":\"60.13\",\"pressureDropBar\":\"13.97\",\"currentStatus\":\"CRITICAL\",\"expectedRange\":\"55-75 bar\",\"outOfRange\":true},{\"code\":\"PL-002-PP-04\",\"positionKm\":34.125,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-05\",\"positionKm\":45.5,\"status\":\"NO_DATA\"}]}"', '"{\"leakDetected\":true,\"confidence\":0.85,\"severity\":\"CRITICAL\",\"estimatedKmFromStart\":22.75,\"estimatedLat\":21.48,\"estimatedLng\":56.495,\"affectedPoints\":[\"PL-002-PP-03\"],\"pressureDrop\":13.97,\"summary\":\"Critical leak detected at PP-03 (km 22.75) with 13.97 bar pressure drop over 83 minutes, falling below safe minimum of 55 bar to 51.84 bar. Immediate shutdown required.\",\"summaryAr\":\"تم اكتشاف تسرب حرج عند نقطة PP-03 (كم 22.75) مع انخفاض ضغط 13.97 بار خلال 83 دقيقة، وانخفض إلى 51.84 بار تحت الحد الآمن 55 بار. يتطلب إيقاف فوري.\",\"rootCause\":\"Severe pipeline rupture or major flange/valve failure at PP-03 location causing rapid gas loss and pressure drop below safe operating limits\",\"predictions\":[\"Continued operation will result in further pressure decline below 50 bar within next 30-60 minutes, risking complete system depressurization\",\"Gas release rate estimated at 8-12% of pipeline volume per hour based on pressure drop velocity, creating significant safety and environmental hazard\",\"Downstream points PP-04 and PP-05 will experience cascading pressure loss within 2-4 hours if leak not isolated immediately\"],\"immediateActions\":[\"EMERGENCY: Isolate PL-002-PP-03 section immediately using upstream valve at PP-02 and downstream valve at PP-04 to contain leak\",\"Evacuate personnel within 500m radius of coordinates 21.48°N, 56.495°E and establish exclusion zone per MoEM emergency protocols\",\"Deploy emergency response team with gas detection equipment to PP-03 location for leak confirmation and source identification\",\"Notify OQ Operations Control Center, MoEM, and Block 61 operator BP Oman immediately as per Oman Gas Safety Regulations\",\"Activate continuous monitoring of PP-02 and PP-04 pressure points to verify isolation effectiveness\"],\"preventiveActions\":[\"Conduct comprehensive integrity assessment of entire PL-002 pipeline using inline inspection tools (smart pigs) focusing on corrosion, weld defects, and mechanical damage\",\"Restore NO_DATA status sensors at PP-01, PP-02, PP-04, and PP-05 immediately to enable full pipeline monitoring and early leak detection capability\",\"Implement enhanced cathodic protection monitoring program given 5-year pipeline age and Khazzan desert soil conditions that accelerate external corrosion\",\"Establish automated pressure differential alarm system with ≥5 bar/hour threshold to enable faster leak response before critical pressure loss occurs\"]}"', 'Critical leak detected at PP-03 (km 22.75) with 13.97 bar pressure drop over 83 minutes, falling below safe minimum of 55 bar to 51.84 bar. Immediate shutdown required.', 0.85, NULL, NULL, NULL, 1, 1, NULL, NULL, NULL, NULL, 1779380738247);
INSERT INTO "AIDecision" ("id", "type", "provider", "modelUsed", "inputData", "outputData", "reasoning", "confidence", "tokensInput", "tokensOutput", "durationMs", "autonomous", "requiresHuman", "visionDetectionId", "telemetryId", "alertId", "incidentId", "createdAt") VALUES ('cmpfpfetm001hhpgjt06ifdcm', 'PIPELINE_LEAK_ANALYSIS', 'CLAUDE', 'claude-sonnet-4-5-20250929', '"{\"pipelineId\":\"pl-002\",\"dataSummary\":[{\"code\":\"PL-002-PP-01\",\"positionKm\":0,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-02\",\"positionKm\":11.375,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-03\",\"positionKm\":22.75,\"latitude\":21.48,\"longitude\":56.495,\"readingsCount\":12,\"firstReading\":{\"pressure\":\"64.24\",\"time\":\"2026-05-21T15:04:57.851Z\"},\"lastReading\":{\"pressure\":\"43.04\",\"time\":\"2026-05-21T16:27:27.851Z\"},\"averagePressure\":\"56.55\",\"pressureDropBar\":\"21.20\",\"currentStatus\":\"CRITICAL\",\"expectedRange\":\"55-75 bar\",\"outOfRange\":true},{\"code\":\"PL-002-PP-04\",\"positionKm\":34.125,\"status\":\"NO_DATA\"},{\"code\":\"PL-002-PP-05\",\"positionKm\":45.5,\"status\":\"NO_DATA\"}]}"', '"{\"leakDetected\":true,\"confidence\":0.92,\"severity\":\"CRITICAL\",\"estimatedKmFromStart\":22.75,\"estimatedLat\":21.48,\"estimatedLng\":56.495,\"affectedPoints\":[\"PL-002-PP-03\"],\"pressureDrop\":21.2,\"summary\":\"Critical leak detected at PP-03 (22.75 km) with catastrophic pressure drop of 21.2 bar in 83 minutes, falling below safe minimum to 43.04 bar. Immediate emergency shutdown required.\",\"summaryAr\":\"تم اكتشاف تسرب حرج عند نقطة PP-03 (22.75 كم) مع انخفاض كارثي في الضغط بمقدار 21.2 بار خلال 83 دقيقة، منخفضاً إلى 43.04 بار تحت الحد الآمن. يتطلب إيقاف طارئ فوري.\",\"rootCause\":\"Major pipeline rupture or catastrophic valve failure at PP-03 location - pressure drop rate of 15.3 bar/hour exceeds all normal operational parameters and indicates severe structural compromise\",\"predictions\":[\"Continued operation will result in complete pressure loss within 2-3 hours and potential environmental gas release\",\"Downstream pressure points PP-04 and PP-05 will experience cascading pressure failures if not already affected (sensor malfunction suspected)\",\"Gas flow rate reduction of 60-75% indicates major breach requiring pipeline segment replacement rather than repair\"],\"immediateActions\":[\"EMERGENCY: Activate ESD (Emergency Shutdown) system immediately and isolate PL-002 pipeline segment between PP-02 and PP-04\",\"Dispatch emergency response team to coordinates 21.48°N, 56.495°E with gas detection equipment and establish 500m safety perimeter\",\"Notify MoEM Emergency Operations Center, PDO Khazzan facility, and activate Block 61 emergency response protocol per Oman Gas Safety Regulations 2019\",\"Verify status of PP-01, PP-02, PP-04, PP-05 sensors - restore telemetry to assess full pipeline integrity\",\"Initiate controlled depressurization of upstream section and monitor for gas migration or surface venting\"],\"preventiveActions\":[\"Implement 24/7 real-time pressure monitoring with redundant sensors at all pressure points - current NO_DATA status at 4 of 5 points is unacceptable for critical gas infrastructure\",\"Conduct immediate integrity assessment of entire PL-002 pipeline using inline inspection tools (smart pigs) focusing on corrosion, stress cracking, and weld integrity given 5-year service life in desert conditions\",\"Establish automated alarm thresholds at ±5 bar/30min with direct integration to SCADA and mobile alert systems for operations team\",\"Review and upgrade cathodic protection systems along entire route - desert soil conditions and temperature extremes accelerate external corrosion on gas pipelines\"]}"', 'Critical leak detected at PP-03 (22.75 km) with catastrophic pressure drop of 21.2 bar in 83 minutes, falling below safe minimum to 43.04 bar. Immediate emergency shutdown required.', 0.92, NULL, NULL, NULL, 1, 1, NULL, NULL, NULL, NULL, 1779380870602);
INSERT INTO "AIDecision" ("id", "type", "provider", "modelUsed", "inputData", "outputData", "reasoning", "confidence", "tokensInput", "tokensOutput", "durationMs", "autonomous", "requiresHuman", "visionDetectionId", "telemetryId", "alertId", "incidentId", "createdAt") VALUES ('cmpfpfwai0020hpgjwxnnimoi', 'PIPELINE_LEAK_ANALYSIS', 'CLAUDE', 'claude-sonnet-4-5-20250929', '"{\"pipelineId\":\"pl-001\",\"dataSummary\":[{\"code\":\"PL-001-PP-01\",\"positionKm\":0,\"status\":\"NO_DATA\"},{\"code\":\"PL-001-PP-02\",\"positionKm\":71.25,\"status\":\"NO_DATA\"},{\"code\":\"PL-001-PP-03\",\"positionKm\":142.5,\"latitude\":22.89585,\"longitude\":56.579,\"readingsCount\":12,\"firstReading\":{\"pressure\":\"72.15\",\"time\":\"2026-05-21T15:05:22.948Z\"},\"lastReading\":{\"pressure\":\"65.24\",\"time\":\"2026-05-21T16:27:52.948Z\"},\"averagePressure\":\"70.11\",\"pressureDropBar\":\"6.92\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-04\",\"positionKm\":213.75,\"status\":\"NO_DATA\"},{\"code\":\"PL-001-PP-05\",\"positionKm\":285,\"status\":\"NO_DATA\"}]}"', '"{\"leakDetected\":true,\"confidence\":0.72,\"severity\":\"MEDIUM\",\"estimatedKmFromStart\":142.5,\"estimatedLat\":22.89585,\"estimatedLng\":56.579,\"affectedPoints\":[\"PL-001-PP-03\"],\"pressureDrop\":6.92,\"summary\":\"Moderate pressure drop of 6.92 bar detected at PP-03 (km 142.5) over 82 minutes, exceeding normal variation threshold. Leak probability is medium due to limited sensor data from adjacent points.\",\"summaryAr\":\"تم اكتشاف انخفاض متوسط في الضغط بمقدار 6.92 بار عند نقطة PP-03 (كم 142.5) خلال 82 دقيقة، متجاوزاً حد التباين الطبيعي. احتمالية التسرب متوسطة بسبب محدودية بيانات أجهزة الاستشعار المجاورة.\",\"rootCause\":\"Possible small to medium leak at or near PP-03 location, potentially caused by corrosion, mechanical stress, or third-party interference in desert terrain\",\"predictions\":[\"If leak confirmed, pressure will continue dropping at PP-03 and downstream points will show similar patterns within 1-2 hours\",\"Gas flow rate reduction of 8-15% expected if leak persists, affecting Sohar delivery commitments\",\"Without intervention, pressure may drop below 60 bar safe minimum within 4-6 hours, triggering automatic shutdown\"],\"immediateActions\":[\"Dispatch emergency inspection team to PP-03 location (22.89585°N, 56.579°E) immediately with leak detection equipment\",\"Investigate why PP-01, PP-02, PP-04, and PP-05 sensors show NO_DATA status - restore telemetry immediately to confirm leak location\",\"Notify MoEM Operations Control Center and prepare for potential partial shutdown if pressure drops below 62 bar\",\"Increase monitoring frequency at PP-03 to 5-minute intervals and establish direct communication with Khazzan source station\"],\"preventiveActions\":[\"Conduct comprehensive inline inspection (ILI) of 120-165 km section using smart pigs to assess corrosion and mechanical damage\",\"Repair or replace faulty telemetry systems at four non-reporting pressure points to ensure complete pipeline visibility\",\"Review cathodic protection system effectiveness in desert conditions and enhance corrosion monitoring program\",\"Implement redundant pressure monitoring with additional sensors at 35 km intervals per MoEM updated guidelines\"]}"', 'Moderate pressure drop of 6.92 bar detected at PP-03 (km 142.5) over 82 minutes, exceeding normal variation threshold. Leak probability is medium due to limited sensor data from adjacent points.', 0.72, NULL, NULL, NULL, 1, 0, NULL, NULL, NULL, NULL, 1779380893242);
INSERT INTO "AIDecision" ("id", "type", "provider", "modelUsed", "inputData", "outputData", "reasoning", "confidence", "tokensInput", "tokensOutput", "durationMs", "autonomous", "requiresHuman", "visionDetectionId", "telemetryId", "alertId", "incidentId", "createdAt") VALUES ('cmpfqx083003bhpgjjabwda7r', 'PIPELINE_LEAK_ANALYSIS', 'CLAUDE', 'claude-sonnet-4-5-20250929', '"{\"pipelineId\":\"pl-001\",\"dataSummary\":[{\"code\":\"PL-001-PP-01\",\"positionKm\":0,\"latitude\":21.45,\"longitude\":56.45,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"71.99\",\"time\":\"2026-05-21T15:56:30.803Z\"},\"lastReading\":{\"pressure\":\"71.99\",\"time\":\"2026-05-21T15:56:30.803Z\"},\"averagePressure\":\"71.99\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-02\",\"positionKm\":71.25,\"latitude\":22.172925,\"longitude\":56.5145,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"72.62\",\"time\":\"2026-05-21T15:56:30.816Z\"},\"lastReading\":{\"pressure\":\"72.62\",\"time\":\"2026-05-21T15:56:30.816Z\"},\"averagePressure\":\"72.62\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-03\",\"positionKm\":142.5,\"latitude\":22.89585,\"longitude\":56.579,\"readingsCount\":12,\"firstReading\":{\"pressure\":\"72.53\",\"time\":\"2026-05-21T15:46:39.354Z\"},\"lastReading\":{\"pressure\":\"50.61\",\"time\":\"2026-05-21T17:09:09.354Z\"},\"averagePressure\":\"64.25\",\"pressureDropBar\":\"21.92\",\"currentStatus\":\"CRITICAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":true},{\"code\":\"PL-001-PP-04\",\"positionKm\":213.75,\"latitude\":23.618775,\"longitude\":56.6435,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"70.34\",\"time\":\"2026-05-21T15:56:30.837Z\"},\"lastReading\":{\"pressure\":\"70.34\",\"time\":\"2026-05-21T15:56:30.837Z\"},\"averagePressure\":\"70.34\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false},{\"code\":\"PL-001-PP-05\",\"positionKm\":285,\"latitude\":24.3417,\"longitude\":56.708,\"readingsCount\":1,\"firstReading\":{\"pressure\":\"73.57\",\"time\":\"2026-05-21T15:56:30.847Z\"},\"lastReading\":{\"pressure\":\"73.57\",\"time\":\"2026-05-21T15:56:30.847Z\"},\"averagePressure\":\"73.57\",\"pressureDropBar\":\"0.00\",\"currentStatus\":\"NORMAL\",\"expectedRange\":\"60-85 bar\",\"outOfRange\":false}]}"', '"{\"leakDetected\":true,\"confidence\":0.95,\"severity\":\"CRITICAL\",\"estimatedKmFromStart\":142.5,\"estimatedLat\":22.89585,\"estimatedLng\":56.579,\"affectedPoints\":[\"PL-001-PP-03\"],\"pressureDrop\":21.92,\"summary\":\"Critical leak detected at PP-03 (142.5 km) with catastrophic pressure drop of 21.92 bar over 83 minutes, falling from 72.53 to 50.61 bar and breaching minimum safe pressure of 60 bar.\",\"summaryAr\":\"تم اكتشاف تسرب حرج عند نقطة PP-03 (142.5 كم) مع انخفاض كارثي في الضغط بمقدار 21.92 بار خلال 83 دقيقة، حيث انخفض من 72.53 إلى 50.61 بار وتجاوز الحد الأدنى الآمن للضغط 60 بار.\",\"rootCause\":\"Major pipeline rupture or catastrophic valve failure at PP-03 location - the isolated nature of the pressure drop (upstream and downstream points remain normal) indicates localized structural failure rather than operational issue. Given 8-year pipeline age and desert conditions, possible causes include: external corrosion, third-party damage, or weld failure.\",\"predictions\":[\"Gas release rate estimated at 15,000-25,000 m³/hour based on pressure drop velocity - immediate environmental and safety hazard within 500m radius\",\"Downstream pressure at PP-04 and PP-05 will begin dropping within 30-45 minutes as the leak propagates if not isolated immediately\",\"Complete pipeline depressurization at PP-03 segment expected within 2-3 hours if emergency shutdown not executed\"],\"immediateActions\":[\"EMERGENCY SHUTDOWN: Immediately close isolation valves upstream (between PP-02 and PP-03) and downstream (between PP-03 and PP-04) to isolate the 71.25 km segment\",\"Evacuate all personnel within 1 km radius of PP-03 location (22.89585°N, 56.579°E) and establish exclusion zone - notify Oman Civil Defence and Royal Oman Police\",\"Deploy emergency response team with gas detection equipment to PP-03 location - assess for fire/explosion risk and environmental impact to surrounding desert area\"],\"preventiveActions\":[\"Conduct immediate inline inspection (ILI) of entire PL-001 pipeline using magnetic flux leakage and ultrasonic tools to identify corrosion, cracking, or wall thinning in other segments\",\"Implement enhanced cathodic protection monitoring and upgrade coating systems in high-risk desert exposure areas - increase inspection frequency from annual to quarterly for 2018-vintage pipelines per MoEM guidelines\"]}"', 'Critical leak detected at PP-03 (142.5 km) with catastrophic pressure drop of 21.92 bar over 83 minutes, falling from 72.53 to 50.61 bar and breaching minimum safe pressure of 60 bar.', 0.95, NULL, NULL, 17577, 1, 1, NULL, NULL, NULL, NULL, 1779383371107);
INSERT INTO "AIDecision" ("id", "type", "provider", "modelUsed", "inputData", "outputData", "reasoning", "confidence", "tokensInput", "tokensOutput", "durationMs", "autonomous", "requiresHuman", "visionDetectionId", "telemetryId", "alertId", "incidentId", "createdAt") VALUES ('cmpgxv82z0006hpkxn60ek9ph', 'DAILY_FORECAST', 'CLAUDE', 'claude-sonnet-4-5-20250929', '{"today":"2026-05-22","tomorrow":"2026-05-23","incidentsYesterday":1,"incidentSamples":[{"type":"PIPELINE_LEAK","severity":"CRITICAL","location":"PL-001 — km 142.5","siteId":"site-khazzan"}],"incidentsLast7Days":11,"activePermits":1,"permitSamples":[{"type":"ELECTRICAL","riskLevel":"HIGH","location":"MCC Room","siteId":"site-block60"}],"pendingAlerts":0,"activeLeaks":1,"weatherLatest":[{"temperature":39.2,"humidity":30,"windSpeed":12,"aqi":55,"condition":"CLEAR","siteId":"site-karim"},{"temperature":40.5,"humidity":27,"windSpeed":18,"aqi":68,"condition":"CLEAR","siteId":"site-rima"},{"temperature":34.8,"humidity":65,"windSpeed":32,"aqi":72,"condition":"CLOUDY","siteId":"site-musandam"},{"temperature":40.1,"humidity":24,"windSpeed":28,"aqi":82,"condition":"CLEAR","siteId":"site-block61"},{"temperature":42.3,"humidity":18,"windSpeed":15,"aqi":95,"condition":"CLEAR","siteId":"site-block65"}],"sites":[{"code":"KHZ-001","name":"Khazzan Gas Field","risk":"MEDIUM","status":"ACTIVE"},{"code":"MKM-001","name":"Makarem Sour Gas Plant","risk":"HIGH","status":"ACTIVE"},{"code":"BL60-001","name":"Block 60","risk":"MEDIUM","status":"ACTIVE"},{"code":"BL61-001","name":"Block 61 / Khazzan-Ghazeer","risk":"MEDIUM","status":"ACTIVE"},{"code":"BL65-001","name":"Block 65","risk":"LOW","status":"ACTIVE"},{"code":"BL53-001","name":"Block 53 / Mukhaizna","risk":"HIGH","status":"ACTIVE"},{"code":"KRM-001","name":"Karim Cluster","risk":"LOW","status":"ACTIVE"},{"code":"RMA-001","name":"Rima Cluster","risk":"LOW","status":"ACTIVE"},{"code":"MSD-001","name":"Musandam LPG Terminal","risk":"CRITICAL","status":"ACTIVE"}]}', '{"content":"```json\n{\n  \"overallRisk\": \"HIGH\",\n  \"headline\": \"Critical pipeline leak at Khazzan remains active amid extreme heat (42°C+) and elevated AQI; high-risk electrical work at Block 60 compounds exposure.\",\n  \"headlineAr\": \"تسرب خطير نشط في خزان مع حرارة شديدة (42°م+) وجودة هواء متدنية؛ أعمال كهربائية عالية المخاطر في القطاع 60 تزيد التعرض\",\n  \"riskFactors\": [\n    {\n      \"factor\": \"Active CRITICAL pipeline leak at Khazzan (PL-001 km 142.5) unresolved\",\n      \"factorAr\": \"تسرب أنابيب حرج نشط في خزان (خط 001 كم 142.5) غير محلول\",\n      \"weight\": \"CRITICAL\"\n    },\n    {\n      \"factor\": \"Extreme heat stress: Block 65 at 42.3°C, multiple sites above 40°C\",\n      \"factorAr\": \"إجهاد حراري شديد: القطاع 65 عند 42.3°م، مواقع متعددة فوق 40°م\",\n      \"weight\": \"HIGH\"\n    },\n    {\n      \"factor\": \"Poor air quality at Block 65 (AQI 95) and Block 61 (AQI 82) affecting respiratory safety\",\n      \"factorAr\": \"جودة هواء رديئة في القطاع 65 (مؤشر 95) والقطاع 61 (مؤشر 82) تؤثر على السلامة التنفسية\",\n      \"weight\": \"HIGH\"\n    },\n    {\n      \"factor\": \"High-risk electrical permit active at Block 60 MCC Room during heat wave\",\n      \"factorAr\": \"تصريح كهربائي عالي المخاطر نشط في غرفة MCC بالقطاع 60 خلال موجة حر\",\n      \"weight\": \"MEDIUM\"\n    },\n    {\n      \"factor\": \"11 incidents in past 7 days indicates deteriorating safety trend\",\n      \"factorAr\": \"11 حادثة في آخر 7 أيام تشير إلى تدهور اتجاه السلامة\",\n      \"weight\": \"MEDIUM\"\n    }\n  ],\n  \"recommendations\": [\n    \"Deploy emergency response team to Khazzan PL-001 leak site; establish 500m exclusion zone and continuous gas monitoring until isolation confirmed\",\n    \"Implement Code Red heat protocol: suspend non-essential outdoor work 11:00-16:00 at Block 65, Block 61, and Rima; mandatory 15-min breaks every hour with hydration stations\",\n    \"Issue respiratory PPE (P95 minimum) for all personnel at Block 65 and Block 61; consi