INSERT INTO "LeakAlert" ("id", "alertNumber", "pipelineId", "detectedAt", "severity", "estimatedKmFromStart", "estimatedLat", "estimatedLng", "confidence", "pressureDrop", "affectedPoints", "aiAnalysis", "aiSummary", "status", "resolvedAt", "resolvedBy", "resolution", "createdAt", "updatedAt", "idempotencyKey") VALUES ('cmpfqx087003dhpgjboa0k63m', 'LEAK-2026-0001', 'pl-001', 1779383371112, 'CRITICAL', 142.5, 22.89585, 56.579, 0.95, 21.92, '["PL-001-PP-03"]', '{"leakDetected":true,"confidence":0.95,"severity":"CRITICAL","estimatedKmFromStart":142.5,"estimatedLat":22.89585,"estimatedLng":56.579,"affectedPoints":["PL-001-PP-03"],"pressureDrop":21.92,"summary":"Critical leak detected at PP-03 (142.5 km) with catastrophic pressure drop of 21.92 bar over 83 minutes, falling from 72.53 to 50.61 bar and breaching minimum safe pressure of 60 bar.","summaryAr":"تم اكتشاف تسرب حرج عند نقطة PP-03 (142.5 كم) مع انخفاض كارثي في الضغط بمقدار 21.92 بار خلال 83 دقيقة، حيث انخفض من 72.53 إلى 50.61 بار وتجاوز الحد الأدنى الآمن للضغط 60 بار.","rootCause":"Major pipeline rupture or catastrophic valve failure at PP-03 location - the isolated nature of the pressure drop (upstream and downstream points remain normal) indicates localized structural failure rather than operational issue. Given 8-year pipeline age and desert conditions, possible causes include: external corrosion, third-party damage, or weld failure.","predictions":["Gas release rate estimated at 15,000-25,000 m³/hour based on pressure drop velocity - immediate environmental and safety hazard within 500m radius","Downstream pressure at PP-04 and PP-05 will begin dropping within 30-45 minutes as the leak propagates if not isolated immediately","Complete pipeline depressurization at PP-03 segment expected within 2-3 hours if emergency shutdown not executed"],"immediateActions":["EMERGENCY SHUTDOWN: Immediately close isolation valves upstream (between PP-02 and PP-03) and downstream (between PP-03 and PP-04) to isolate the 71.25 km segment","Evacuate all personnel within 1 km radius of PP-03 location (22.89585°N, 56.579°E) and establish exclusion zone - notify Oman Civil Defence and Royal Oman Police","Deploy emergency response team with gas detection equipment to PP-03 location - assess for fire/explosion risk and environmental impact to surrounding desert area"],"preventiveActions":["Conduct immediate inline inspection (ILI) of entire PL-001 pipeline using magnetic flux leakage and ultrasonic tools to identify corrosion, cracking, or wall thinning in other segments","Implement enhanced cathodic protection monitoring and upgrade coating systems in high-risk desert exposure areas - increase inspection frequency from annual to quarterly for 2018-vintage pipelines per MoEM guidelines"]}', 'Critical leak detected at PP-03 (142.5 km) with catastrophic pressure drop of 21.92 bar over 83 minutes, falling from 72.53 to 50.61 bar and breaching minimum safe pressure of 60 bar.', 'ACTIVE', NULL, NULL, NULL, 1779383371112, 1779383371112, NULL);
INSERT INTO "LeakAlert" ("id", "alertNumber", "pipelineId", "detectedAt", "severity", "estimatedKmFromStart", "estimatedLat", "estimatedLng", "confidence", "pressureDrop", "affectedPoints", "aiAnalysis", "aiSummary", "status", "resolvedAt", "resolvedBy", "resolution", "createdAt", "updatedAt", "idempotencyKey") VALUES ('cmpgyek53001hhp0crgddr4lu', 'LEAK-2026-0002', 'pl-001', 1779456413560, 'CRITICAL', 35.6, 21.811463, 56.48225, 0.95, 22, '["PL-001-PP-02","PL-001-PP-03","PL-001-PP-04","PL-001-PP-05"]', '{"leakDetected":true,"confidence":0.95,"severity":"CRITICAL","estimatedKmFromStart":35.6,"estimatedLat":21.811463,"estimatedLng":56.48225,"affectedPoints":["PL-001-PP-02","PL-001-PP-03","PL-001-PP-04","PL-001-PP-05"],"pressureDrop":22,"summary":"Critical leak detected between PP-01 and PP-02. Catastrophic pressure drop of 22 bar across 4 downstream sensors while PP-01 remains stable, indicating major rupture approximately 35.6 km from pipeline origin.","summaryAr":"تم اكتشاف تسرب حرج بين PP-01 و PP-02. انخفاض كارثي في الضغط بمقدار 22 بار عبر 4 مستشعرات لاحقة بينما يظل PP-01 مستقرًا، مما يشير إلى تразрыв كبير على بعد حوالي 35.6 كم من بداية خط الأنابيب.","rootCause":"Major pipeline rupture or catastrophic valve failure between PP-01 (km 0) and PP-02 (km 71.25). The uniform 22-bar pressure drop across all downstream points while upstream remains normal indicates complete loss of pressure integrity in the segment, likely full-bore rupture or complete valve seat failure.","immediateActions":["EMERGENCY SHUTDOWN: Immediately isolate PL-001 at source and close all block valves upstream of PP-01","EVACUATE: Establish 500m exclusion zone around estimated leak location (21.811°N, 56.482°E) and evacuate all personnel","DISPATCH: Send emergency response team with gas detection equipment to km 35.6 sector for visual confirmation and containment","NOTIFY: Alert OQ Emergency Operations Center, Civil Defense, and Ministry of Energy - declare Level 1 emergency","MONITOR: Continuous surveillance of PP-01 pressure decay rate to confirm isolation effectiveness"]}', 'Critical leak detected between PP-01 and PP-02. Catastrophic pressure drop of 22 bar across 4 downstream sensors while PP-01 remains stable, indicating major rupture approximately 35.6 km from pipeline origin.', 'ACTIVE', NULL, NULL, NULL, 1779456413560, 1779456413560, '7b59cc9b95bf60a413170311a2907aed');
